joi_block.script:
n := 0
triggered := false
if ((#MultiButton).multiButton_button4 == "pushed") {
if (triggered == false) {
if (n % 3 == 0) {
(#Light #LivingRoom).light_moveToBrightness(25, 0)
}
else if (n % 3 == 1) {
(#Light #LivingRoom).light_moveToBrightness(50, 0)
}
else {
(#Light #LivingRoom).light_moveToBrightness(75, 0)
}
triggered = true
}
}
else {
triggered = false
}
n = n + 1

